const items = $input.all();
const results = [];

items.forEach(item => {
  const textContent = item.json.text_content || '';
  const documentId = item.json.document_id;
  const collectionName = item.json.collection_name || 'knowledge_base';

  const paragraphs = textContent.split('\n\n');
  const MAX_CHARS = 2000;
  const OVERLAP_CHARS = 200;

  let currentChunk = '';
  let chunkIndex = 0;

  for (let i = 0; i < paragraphs.length; i++) {
    const p = paragraphs[i];

    if ((currentChunk.length + p.length) > MAX_CHARS && currentChunk.length > 0) {
      results.push({
        json: {
          chunk_index: chunkIndex++,
          chunk_text: currentChunk.trim(),
          document_id: documentId,
          collection_name: collectionName
        }
      });

      let overlapText = currentChunk.slice(-OVERLAP_CHARS);
      const lastSpace = overlapText.indexOf(' ');
      if (lastSpace !== -1 && lastSpace < OVERLAP_CHARS / 2) {
         overlapText = overlapText.slice(lastSpace + 1);
      }
      currentChunk = overlapText + '\n\n' + p;
    } else {
      currentChunk += (currentChunk ? '\n\n' : '') + p;
    }
  }

  if (currentChunk.trim().length > 0) {
    results.push({
      json: {
        chunk_index: chunkIndex++,
        chunk_text: currentChunk.trim(),
        document_id: documentId,
        collection_name: collectionName
      }
    });
  }
});

return results;

const embeddingResponse = $json.response;
const chunkData = $('Process Each Chunk').first().json;

// UTIL__AICall returns the raw Hugging Face response for embeddings.
// Hugging Face feature-extraction returns [[0.1, 0.2, ...]] (nested array).
// We need to extract the inner array and format it as a pgvector string '[0.1,0.2,...]'.
let vector = embeddingResponse;

// Handle nested array from Hugging Face
if (Array.isArray(vector) && Array.isArray(vector[0])) {
  vector = vector[0];
}

// If it's still an object/array, convert to pgvector string format
if (Array.isArray(vector)) {
  vector = '[' + vector.join(',') + ']';
}

return {
  json: {
    document_id: chunkData.document_id,
    chunk_index: chunkData.chunk_index,
    chunk_text: chunkData.chunk_text,
    embedding: vector,
    collection_name: chunkData.collection_name,
    embedding_model: 'sentence-transformers/all-MiniLM-L6-v2'
  }
};
